1	export interface ItemSpec {
2	  type: string;
3	}
4	
5	export interface Customer {
6	  yearsWithMHPCO: number;
7	}
8	
9	export interface QuoteInput {
10	  customer: Customer;
11	  items: ItemSpec[];
12	}
13	
14	export interface QuoteResult {
15	  premium: number;
16	}
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	};
26	
27	function basePremiumFor(item: ItemSpec): number {
28	  return BASE_PREMIUMS[item.type] ?? 0;
29	}
30	
31	export function quote(input: QuoteInput): QuoteResult {
32	  const policyBasePremium = input.items.reduce(
33	    (sum, item) => sum + basePremiumFor(item),
34	    0
35	  );
36	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
37	  return {
38	    premium: policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
39	  };
40	}
41	
42	export function claim(): unknown {
43	  return undefined;
44	}
